const email = $input.first().json;

const sender = email.from?.emailAddress?.address || email.sender || 'unknown';
const subject = email.subject || '';
const body = (email.bodyPreview || email.body || '').substring(0, 300).toLowerCase();
const text = (subject + ' ' + body).toLowerCase();

let category = 'COLD';
let score = 30;
let action = 'Add to nurture list';

const hotKeywords = ['buy', 'purchase', 'order', 'quote', 'demo', 'interested', 'want to buy', 'pricing', 'cost', 'price', 'investment', 'proposal'];
const warmKeywords = ['information', 'learn more', 'details', 'interested', 'tell me', 'how does', 'can you', 'more info'];
const spamKeywords = ['viagra', 'casino', 'lottery', 'unsubscribe', 'click here', 'urgent action', 'limited time'];

if (spamKeywords.some(kw => text.includes(kw))) {
  category = 'SPAM';
  score = 0;
  action = 'Mark as spam and delete';
} else if (hotKeywords.some(kw => text.includes(kw))) {
  category = 'HOT';
  score = 90;
  action = 'Immediate follow-up required - HIGH PRIORITY';
} else if (warmKeywords.some(kw => text.includes(kw))) {
  category = 'WARM';
  score = 60;
  action = 'Schedule follow-up meeting';
}

return {
  sender: sender,
  subject: subject,
  category: category,
  score: score,
  summary: `${sender} - ${category} lead (Score: ${score})`,
  action: action,
  timestamp: new Date().toISOString()
};
